const files = $input.all().map(i => {
  const f = i.json;
  const mod = f.modifiedTime ? new Date(f.modifiedTime).toLocaleDateString('pt-BR') : '?';
  const mime = f.mimeType || '';
  let tipo = 'arquivo';
  if (mime.includes('document')) tipo = 'Doc';
  else if (mime.includes('spreadsheet')) tipo = 'Planilha';
  else if (mime.includes('presentation')) tipo = 'Slides';
  else if (mime.includes('pdf')) tipo = 'PDF';
  else if (mime.includes('text')) tipo = 'Texto';
  return `- [${tipo}] ${f.name} | Modificado: ${mod} | ID: ${f.id}`;
});
return [{json:{result: files.length ? files.join('\n') : 'Nenhum arquivo encontrado nos ultimos 14 dias.'}}];

